section.code:
{
  "$schema": "https://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/vr-design-patterns.json",
  "type": "object",
  "required": [
    "__faion_header__",
    "scenes",
    "locomotion",
    "ui_anchoring",
    "accessibility"
  ],
  "properties": {
    "__faion_header__": {
      "type": "object",
      "required": [
        "methodology",
        "version",
        "produces"
      ],
      "properties": {
        "methodology": {
          "const": "vr-design-patterns"
        },
        "version": {
          "type": "string"
        },
        "produces": {
          "const": "spec"
        }
      }
    },
    "scenes": {
      "type": "array",
      "minItems": 1,
      "items": {
        "type": "object",
        "required": [
          "id",
          "has_ground",
          "has_horizon"
        ],
        "properties": {
          "id": {
            "type": "string"
          },
          "has_ground": {
            "type": "boolean",
            "const": true
          },
          "has_horizon": {
            "type": "boolean",
            "const": true
          }
        }
      }
    },
    "locomotion": {
      "type": "object",
      "required": [
        "default",
        "options",
        "turning"
      ],
      "properties": {
        "default": {
          "enum": [
            "teleport"
          ]
        },
        "options": {
          "type": "array",
          "items": {
            "enum": [
              "teleport",
              "smooth",
              "arm-swing"
            ]
          },
          "minItems": 2
        },
        "turning": {
          "type": "object",
          "required": [
            "default",
            "options"
          ],
          "properties": {
            "default": {
              "enum": [
                "snap"
              ]
            },
            "options": {
              "type": "array",
              "items": {
                "enum": [
                  "snap",
                  "smooth"
                ]
              },
              "minItems": 2
            }
          }
        }
      }
    },
    "ui_anchoring": {
      "type": "object",
      "required": [
        "primary"
      ],
      "properties": {
        "primary": {
          "enum": [
            "world-anchored",
            "body-anchored"
          ]
        },
        "head_locked_for_safety_only": {
          "type": "boolean",
          "const": true
        }
      }
    },
    "accessibility": {
      "type": "object",
      "required": [
        "seated_toggle",
        "one_handed_path",
        "subtitles",
        "audio_descriptions"
      ],
      "properties": {
        "seated_toggle": {
          "type": "boolean",
          "const": true
        },
        "one_handed_path": {
          "type": "boolean",
          "const": true
        },
        "subtitles": {
          "type": "boolean",
          "const": true
        },
        "audio_descriptions": {
          "type": "boolean",
          "const": true
        }
      }
    }
  }
}

example.code:
{
  "__faion_header__": {
    "methodology": "vr-design-patterns",
    "version": "1.1.0",
    "produces": "spec"
  },
  "scenes": [
    {
      "id": "lobby",
      "has_ground": true,
      "has_horizon": true
    },
    {
      "id": "arena",
      "has_ground": true,
      "has_horizon": true
    }
  ],
  "locomotion": {
    "default": "teleport",
    "options": [
      "teleport",
      "smooth"
    ],
    "turning": {
      "default": "snap",
      "options": [
        "snap",
        "smooth"
      ]
    }
  },
  "ui_anchoring": {
    "primary": "world-anchored",
    "head_locked_for_safety_only": true
  },
  "accessibility": {
    "seated_toggle": true,
    "one_handed_path": true,
    "subtitles": true,
    "audio_descriptions": true
  }
}
